import React from "react";
import { motion } from "framer-motion";
import "./index.css";

export default function App() {
  return (
    <div className="bg-gradient-to-br from-black via-gray-900 to-black text-white min-h-screen overflow-x-hidden">
      <Navbar />
      <Hero />
      <Experience />
      <Projects />
      <Contact />
    </div>
  );
}

function Navbar() {
  return (
    <div className="flex justify-between items-center px-10 py-5 backdrop-blur-xl bg-white/5 sticky top-0 z-50 border-b border-white/10">
      <h1 className="text-xl font-bold tracking-widest">KASHIF</h1>
      <div className="space-x-6 text-sm">
        <a href="#exp" className="hover:text-blue-400 transition">Experience</a>
        <a href="#projects" className="hover:text-blue-400 transition">Projects</a>
        <a href="#contact" className="hover:text-blue-400 transition">Contact</a>
      </div>
    </div>
  );
}

function Hero() {
  return (
    <div className="text-center py-40 px-6">

      <motion.h1
        initial={{ opacity: 0, y: 40 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.8 }}
        className="text-6xl md:text-7xl font-bold tracking-wide"
      >
        Muhammad Kashif
      </motion.h1>

      <motion.p
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ delay: 0.5 }}
        className="mt-6 text-gray-400 text-xl"
      >
        Full Stack Engineer | Real-Time Systems Specialist
      </motion.p>

      <motion.div
        initial={{ opacity: 0, y: 30 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ delay: 0.8 }}
        className="mt-10 bg-white/5 p-8 rounded-2xl backdrop-blur-xl border border-white/10 max-w-2xl mx-auto shadow-xl"
      >
        <p className="text-gray-300 leading-relaxed">
          Results-driven Software Engineer with 3+ years of experience building scalable,
          high-performance real-time applications using React, Node.js, and WebSockets.
        </p>
      </motion.div>


        {/* <button className="px-6 py-2 bg-blue-600 rounded-lg hover:bg-blue-500 transition">
          View Projects
        </button>
        <button className="px-6 py-2 border border-white/20 rounded-lg hover:bg-white/10 transition">
          Contact Me
        </button> */}

   <div className="mt-10 flex justify-center gap-4">
      <a href="#projects">
        <button className="px-6 py-2 bg-blue-600 rounded-lg hover:bg-blue-500 transition">
          View Projects
        </button>
      </a>

      <a href="#contact">
        <button className="px-6 py-2 border border-white/20 rounded-lg hover:bg-white/10 transition">
          Contact Me
        </button>
      </a>
       </div>

    </div>
  );
}

function Experience() {
  return (
    <div id="exp" className="px-10 py-24 relative">
      <h2 className="text-4xl font-bold mb-16 text-center">Experience</h2>

      <div className="max-w-6xl mx-auto relative">
        {/* Vertical line for timeline */}
        <div className="absolute left-1/2 transform -translate-x-1/2 h-full border-l-2 border-blue-600"></div>

        <TimelineItem
          title="Real-Time Air Traffic & Sensor Systems"
          date="2023 - Present"
          desc={
            <>
              Led integration of multiple <strong>sensors</strong> into a large-scale system, coordinating with third-party vendors and cross-functional teams. 
              Managed real-time data pipelines using <strong>WebSockets, TCP, and UDP</strong> for low-latency transmission. Built high-availability <strong>React-Leaflet</strong> applications to monitor air traffic and visualize sensor data live. Implemented dynamic map markers, layers, and popups for aircraft positions, sensor locations, and maintenance alerts. Optimized performance to ensure <strong>24/7 uptime</strong> and system stability.
            </>
          }
          side="left"
        />

        <TimelineItem
          title="Full Stack Web Applications"
          date="2021 - 2023"
          desc={
            <>
              Developed scalable web applications using <strong>React, Node.js, and Express</strong>. Created interactive map drawing tools for polygons, routes, and real-time coordinate capture. Worked in an <strong>agile environment</strong> to prioritize tasks and deliver features efficiently. Ensured responsive design, smooth rendering, and seamless integration with databases for storing air traffic and sensor data.
            </>
          }
          side="right"
        />
      </div>
    </div>
  );
}

function TimelineItem({ title, date, desc, side }) {
  const isLeft = side === "left";

  return (
    <div className={`mb-16 w-full md:w-1/2 ${isLeft ? "md:pr-8 md:ml-auto text-right" : "md:pl-8 md:mr-auto text-left"}`}>
      <motion.div
        initial={{ opacity: 0, x: isLeft ? -50 : 50 }}
        whileInView={{ opacity: 1, x: 0 }}
        viewport={{ once: true }}
        transition={{ duration: 0.8 }}
        className="relative bg-white/5 p-6 rounded-2xl backdrop-blur-xl border border-white/10 shadow-lg"
      >
        <span className="absolute -top-5 w-5 h-5 bg-blue-600 rounded-full left-1/2 transform -translate-x-1/2 border border-white/10"></span>
        <h3 className="text-2xl font-semibold">{title}</h3>
        <p className="text-sm text-blue-400 mt-1">{date}</p>
        <p className="mt-4 text-gray-300 leading-relaxed">{desc}</p>
      </motion.div>
    </div>
  );
}

function Projects() {
  return (
    <div id="projects" className="px-10 py-24">
      <h2 className="text-4xl font-bold mb-12 text-center">Projects</h2>

      <div className="grid md:grid-cols-3 gap-8 max-w-6xl mx-auto">
        <Card
          title="Air Traffic Application"
          desc={
            <>
              Developed a high-availability <strong>React-Leaflet</strong> application for live air traffic monitoring and real-time visualization.
              Implemented dynamic map markers, layers, and popups to show aircraft positions, maintenance alerts, and operational data.
